mapper.update:
UPDATE tnt_tenant_setting SET
    value_json  = CAST(#{valueJson} AS jsonb),
    description = #{description},
    updated_by  = #{updatedBy}
WHERE id = #{id} AND version = #{version}

mapper.select:
